import json, pathlib
states=['North Kordofan','South Kordofan','West Kordofan','North Darfur','East Darfur','Central Darfur','Blue Nile','White Nile','Khartoum','Gezira']
for p in [pathlib.Path('articles/2026/03/26/articles.jsonl'),pathlib.Path('articles/2026/03/25/articles.jsonl')]:
    print('\nCOUNTS',p)
    counts={s:0 for s in states}
    for line in p.open(errors='ignore'):
        try:a=json.loads(line)
        except: continue
        txt=(str(a.get('title') or '')+'\n'+str(a.get('content') or '')).lower()
        for s in states:
            if s.lower() in txt: counts[s]+=1
    for s,c in sorted(counts.items(), key=lambda x:-x[1]):
        if c: print(s,c)
PY

